parameters.jsCode:
const body = $input.first().json.body || $input.first().json;

const email = body.email || body.user_email || '';
const firstName = body.firstName || body.user_first_name || 'there';
const trialEndIso = body.trialEndIso || body.trial_end_date || '';
const upgradeLink = body.upgradeLink || body.upgrade_link || 'https://nova-ops.space/upgrade';

const trialEndDisplay = trialEndIso
  ? new Date(trialEndIso).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  : 'soon';

return [{ json: {
  email,
  firstName,
  trialEndIso,
  trialEndDisplay,
  upgradeLink,
  sentAt: new Date().toISOString()
} }];

